# ── Wildcard resolver ─────────────────────────────────────────────────────────

def resolve_wildcards(text: str) -> str:
    """Replace {a|b|c} patterns with a random choice."""
    def pick(m: re.Match) -> str:
        return random.choice(m.group(1).split("|")).strip()
    while "{" in text:
        text = re.sub(r"\{([^{}]+)\}", pick, text)
    return text

